descricao: {{ $('HTTP Request').item.json.payload.store_name }}
categoria: Alimentação
data: {{ $('HTTP Request').item.json.payload.issuance_date_time.split(' ')[0].split('/').reverse().join('-') }}
valor: {{ $('HTTP Request').item.json.payload.total_paid }}
valor_saldo: -{{ $('HTTP Request').item.json.payload.total_paid }}
meio_pagamento: {{ $('HTTP Request').item.json.payload.payment_method.toLowerCase().includes('cartão de') ? $('HTTP Request').item.json.payload.payment_method.toLowerCase().substring(10) : $('HTTP Request').item.json.payload.payment_method.toLowerCase() }}
fluxo: Saída
tags:
  - "#Finanças/Lançamento"
nfe_chave: "{{ $('HTTP Request').item.json.chave }}"
criado_em: {{ new Date().toLocaleString('pt-BR') }}
---
# Registro de Finanças {{ $('HTTP Request').item.json.payload.store_name }}

## Itens da Nota
{{ 
  $('HTTP Request').item.json.payload.items.map((item, index) => {
    const data = $('HTTP Request').item.json.payload.issuance_date_time.split(' ')[0].split('/').reverse().join('');
    const hora = $('HTTP Request').item.json.payload.issuance_date_time.split(' ')[1].replace(':', '').substring(0, 4);
    const pos = (index + 1).toString().padStart(2, '0');
    const nomeLimpo = item.name.replace(/[^a-zA-Z0-9]/g, '_');

    // ESTE É O NOME DO ARQUIVO QUE O FILHO GEROU
    const nomeArquivoFilho = `${data}_${hora}_${pos}_${nomeLimpo}`;

    return `- [[${nomeArquivoFilho}|${item.name}]]: R$ ${item.item_total.toFixed(2)}`;
  }).join('\n') 
}}

